//
		 // stath1_grey_motor : Κώδικάς για Πράσινο Κινητήρα σε Οffline mode
		 // Υλοποιηση της συναρτησης
		 // 
  
  {
    key: "stath1_grey_motor", 
    value: function stath1_grey_motor(block, parameter) {
      var port = parameter.PORT.code;
      var angle = parameter.ANGLE.code / 2;
      this.addInclude("DFRobot_servo", "#include <DFRobot_Servo.h>");
      this.addObject("servo_object_".concat(port), "Servo", "servo_".concat(port)); 
      this.addSetup("servo_setup_".concat(port), "servo_".concat(port, ".attach(").concat(port, ");"));
      this.addCode("servo_".concat(port, ".angle(").concat(angle, ");"));
    }
  },
  
     	 //
		 // stath1_green_motor : Κώδικάς για Πράσινο Κινητήρα σε Οffline mode
		 // Υλοποιηση της συναρτησης
		 // 
  
  {
    key: "stath1_green_motor", 
    value: function stath1_green_motor(block, parameter) {
	  var port = parameter.PORT.code;
      var direction = parameter.DIRECTION.code;
      var speed = parameter.SPEED.code;
      var code = '';
    
      if (direction == 'LOW') {
		code = "90 + ".concat(speed);
      } else {
		code = "90 - ".concat(speed);
      }
	  
	  this.addInclude("DFRobot_servo", "#include <DFRobot_Servo.h>");
	  this.addObject("servo_object_".concat(port), "Servo", "servo_".concat(port)); 
	  this.addSetup("servo_setup_".concat(port), "servo_".concat(port, ".attach(").concat(port, ");"));
   	  this.addCode("servo_".concat(port, ".angle(").concat(code, ");"));       
    }
  }
